export default class AddressItem {
    constructor(element) {
        this.item = element;
    }
    getLatitude() {
        const elem = this.item.querySelector('input[name="latitude"]');
        if (elem)
            return Number(elem.value);
        return null;
    }
    getLongitude() {
        const elem = this.item.querySelector('input[name="longitude"]');
        if (elem)
            return Number(elem.value);
        return null;
    }
    formatDistance(value) {
        if (value >= 1000) {
            return Math.round(value / 1000.0) + " km";
        }
        else if (value >= 100) {
            return Math.round(value) + " m";
        }
        return value.toFixed(1) + " m";
    }
    ;
    setDistance(distance) {
        let distanceElement = this.item.querySelector(".distance");
        if (distanceElement) {
            if (distance != null) {
                distanceElement.innerHTML = this.formatDistance(distance);
            }
            else {
                distanceElement.innerHTML = "-";
            }
        }
    }
}
